(function () {
    var g = window.GrowthPilot = window.GrowthPilot || {};
    var s = document.currentScript;
    g.pixelKey = s && s.getAttribute('data-key') || '';
    g.endpoint = 'https://fetchbot.ai/api/v1/track/';
    g._start = Date.now();
    g._maxScroll = 0;
    g._lastUrl = window.location.href;

    // Simple fingerprint from browser properties
    var fp = [navigator.userAgent, screen.width, screen.height, navigator.language,
    new Date().getTimezoneOffset(), navigator.hardwareConcurrency || ''].join('|');
    g._fp = fp;

    function send(e, d) {
        if (!g.pixelKey) return;
        var p = {
            pixel_key: g.pixelKey,
            event_type: e,
            url: window.location.href,
            referrer: document.referrer,
            timestamp: new Date().toISOString(),
            user_agent: navigator.userAgent,
            screen_width: screen.width,
            screen_height: screen.height,
            viewport_width: window.innerWidth,
            viewport_height: window.innerHeight,
            language: navigator.language,
            fingerprint: g._fp,
            scroll_depth: g._maxScroll,
            time_on_page_ms: Date.now() - g._start
        };
        if (d) for (var k in d) p[k] = d[k];
        var body = JSON.stringify(p);
        try {
            navigator.sendBeacon(g.endpoint + 'event/', body);
        } catch (ex) {
            var x = new XMLHttpRequest();
            x.open('POST', g.endpoint + 'event/', true);
            x.setRequestHeader('Content-Type', 'application/json');
            x.send(body);
        }
    }

    g.track = send;

    // Scroll depth tracking
    window.addEventListener('scroll', function () {
        var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
        var docHeight = Math.max(document.body.scrollHeight, document.documentElement.scrollHeight) - window.innerHeight;
        var pct = docHeight > 0 ? Math.round(scrollTop / docHeight * 100) : 0;
        if (pct > g._maxScroll) g._maxScroll = Math.min(pct, 100);
    }, { passive: true });

    // Click tracking (links and buttons only)
    document.addEventListener('click', function (e) {
        var el = e.target.closest('a,button,[role="button"]');
        if (!el) return;
        send('click', {
            properties: {
                element: el.tagName.toLowerCase(),
                text: (el.textContent || '').trim().substring(0, 100),
                href: el.href || '',
                id: el.id || ''
            }
        });
    });

    // Form submit tracking
    document.addEventListener('submit', function (e) {
        send('form_submit', {
            properties: {
                form_id: e.target.id || '',
                form_action: e.target.action || ''
            }
        });
    });

    // SPA navigation detection (pushState/popState)
    var origPush = history.pushState;
    history.pushState = function () {
        origPush.apply(this, arguments);
        setTimeout(function () {
            if (window.location.href !== g._lastUrl) {
                g._lastUrl = window.location.href;
                g._maxScroll = 0;
                g._start = Date.now();
                send('pageview');
            }
        }, 50);
    };
    window.addEventListener('popstate', function () {
        setTimeout(function () {
            if (window.location.href !== g._lastUrl) {
                g._lastUrl = window.location.href;
                g._maxScroll = 0;
                g._start = Date.now();
                send('pageview');
            }
        }, 50);
    });

    // Initial pageview
    send('pageview');

    // Session end on page unload
    window.addEventListener('beforeunload', function () {
        send('session_end', { duration: Math.round((Date.now() - g._start) / 1000) });
    });
})();
